import { useEffect, useState } from "react";
import { Link, Route, Routes, useNavigate } from "react-router-dom";
import DashboardPage from "./pages/DashboardPage";
import LoginPage from "./pages/LoginPage";
import SignupPage from "./pages/SignupPage";
import WorkspacePage from "./pages/WorkspacePage";
import ProtectedRoute from "./components/ProtectedRoute";
import { useAuth } from "./context/AuthContext";
import api from "./api/client";

const App = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [apiStatus, setApiStatus] = useState("checking");
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    let isMounted = true;

    const checkApiHealth = async () => {
      try {
        await api.get("/health");
        if (isMounted) setApiStatus("connected");
      } catch {
        if (isMounted) setApiStatus("disconnected");
      }
    };

    checkApiHealth();
    const intervalId = setInterval(checkApiHealth, 10000);

    return () => {
      isMounted = false;
      clearInterval(intervalId);
    };
  }, []);

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  const copyUserId = async () => {
    if (!user?.memberId) return;
    try {
      await navigator.clipboard.writeText(user.memberId);
      setCopied(true);
      setTimeout(() => setCopied(false), 1400);
    } catch {
      setCopied(false);
    }
  };

  return (
    <div className="container">
      <nav className="card top-nav">
        <Link className="nav-link" to="/">Dashboard</Link>
        <Link className="nav-link" to="/workspace">Workspace</Link>
        <span className={`status-badge status-${apiStatus}`}>
          API: {apiStatus === "connected" ? "Connected" : apiStatus === "disconnected" ? "Disconnected" : "Checking"}
        </span>
        {!user && <Link to="/login">Login</Link>}
        {!user && <Link to="/signup">Signup</Link>}
        {user && <span className="user-badge">{user.name} ({user.role})</span>}
        {user && (
          <span className="id-chip" title={user.memberId}>
            Member ID: {user.memberId}
          </span>
        )}
        {user && (
          <button type="button" className="copy-id-btn" onClick={copyUserId}>
            {copied ? "Copied" : "Copy Member ID"}
          </button>
        )}
        {user && <button className="logout-btn" onClick={handleLogout}>Logout</button>}
      </nav>

      <Routes>
        <Route
          path="/"
          element={
            <ProtectedRoute>
              <DashboardPage />
            </ProtectedRoute>
          }
        />
        <Route
          path="/workspace"
          element={
            <ProtectedRoute>
              <WorkspacePage />
            </ProtectedRoute>
          }
        />
        <Route path="/login" element={<LoginPage />} />
        <Route path="/signup" element={<SignupPage />} />
      </Routes>
    </div>
  );
};

export default App;
